import json
import re
from collections import defaultdict

children_books = var_functions.query_db_14

with open('/tmp/tmpr8s80_46.json', 'r') as f:
    reviews = json.load(f)

children_book_ids = {book['book_id'] for book in children_books}

def extract_numeric_id(book_id_str):
    match = re.search(r'(book|purchase)id_(\d+)', str(book_id_str))
    if match:
        return int(match.group(2))
    return None

children_books_numeric = {}
for book in children_books:
    numeric_id = extract_numeric_id(book['book_id'])
    if numeric_id is not None:
        children_books_numeric[numeric_id] = book

book_ratings = defaultdict(list)

for review in reviews:
    purchase_id = review['purchase_id']
    numeric_id = extract_numeric_id(purchase_id)
    if numeric_id is not None and numeric_id in children_books_numeric:
        rating = float(review['rating'])
        book_ratings[numeric_id].append(rating)

books_with_high_ratings = []
for numeric_id, ratings in book_ratings.items():
    if len(ratings) > 0:
        avg_rating = sum(ratings) / len(ratings)
        if avg_rating >= 4.5:
            book_info = children_books_numeric[numeric_id]
            books_with_high_ratings.append({
                'title': book_info['title'],
                'book_id': book_info['book_id'],
                'average_rating': round(avg_rating, 2),
                'review_count': len(ratings)
            })

books_with_high_ratings_sorted = sorted(books_with_high_ratings, key=lambda x: x['average_rating'], reverse=True)

print('__RESULT__:')
print(json.dumps(books_with_high_ratings_sorted, indent=2))

